<template src="./template.html"></template>
<style src="./style.css"></style>
<script>
    import { usersTable, dFiles } from '@/idb/db';
    import { LangPack } from './lang';

    export default {
        name: 'OSIPicta',

        props: {
            windowId: { type: String, required: true },
            USERID: {type: Number, default: 0},
            fileData: { type: Object, default: null },
            fileId: { type: [String, Number], default: null },
            fileName: { type: String, default: '' },
            fileType: { type: String, default: '' },
        },

        emits: ['startapp', 'error', 'notification'],

        data() {
            return {
                lang_data: {},
                images: [],
                isLoading: false,
                currentIndex: -1,
                scale: 1,
                infoPanelVisible: false,
                currentImageInfo: {},
                canScrollLeft: false,
                canScrollRight: false,
                selectedThumbnailRef: null,
                saveTimeout: null,
                imageNaturalWidth: 0,
                imageNaturalHeight: 0,
                isZoomed: false,
                isInitialized: false,
                pendingFileData: null,
                pendingFileId: null,
                lastExternalFileId: null,
            }
        },

        computed: {
            currentImage() {
                return this.images[this.currentIndex] || null;                
            },
    
            imageStyle() {
                if (!this.currentImage) return {};
                
                // Применяем transform только если масштаб изменен
                const style = {
                    opacity: this.isLoading ? 0.5 : 1,
                    transition: 'opacity 0.3s ease, transform 0.3s ease',
                    maxWidth: this.isZoomed ? 'none' : '100%',
                    maxHeight: this.isZoomed ? 'none' : '100%',
                    width: this.isZoomed ? 'auto' : 'auto',
                    height: this.isZoomed ? 'auto' : 'auto'
                };
                
                // Добавляем transform только если масштаб не 1
                if (this.scale !== 1) {
                    style.transform = `scale(${this.scale})`;
                    style.transformOrigin = 'center center';
                }
                
                return style;
            }
        },

        watch: {
            fileId: {
                async handler(newId) {
                    if (!newId) return;
                    if (!this.isInitialized) {
                        this.pendingFileId = newId;
                        return;
                    }

                    try {
                        // Защита от повторных срабатываний при re-render/reupdate окон (например, number ↔ string)
                        const normalizedId = String(newId);
                        if (this.lastExternalFileId === normalizedId) return;
                        this.lastExternalFileId = normalizedId;

                        const fileData = await dFiles.getInfo(newId);
                        if (fileData) await this.loadFileFromData(fileData, { replaceList: true });
                    } catch (error) {
                        console.error('Loading file Error:', error);
                    }
                },
                immediate: true
            },

            fileData: {
                async handler(newVal) {
                    if (!newVal) return;
                    if (!this.isInitialized) {
                        this.pendingFileData = newVal;
                        return;
                    }

                    if (newVal?.id !== undefined && newVal?.id !== null) {
                        const normalizedId = String(newVal.id);
                        if (this.lastExternalFileId === normalizedId) return;
                        this.lastExternalFileId = normalizedId;
                    }

                    await this.loadFileFromData(newVal, { replaceList: true });
                },
                immediate: true,
                deep: false,
            },
        },

        methods: {
            // Инициализация из IDB
            async initFromIDB() {
                if (!this.windowId) {
                    console.error('OSIPicta: windowId is missing');
                    return;
                }

                const savedState = await usersTable.windstates.getById(this.USERID, this.windowId);
                console.log('savedState', savedState);

                if (savedState) {
                    this.images = savedState.images || [];
 
                    if (savedState && this.images.length > 0) {
                        this.currentIndex = (savedState.currentIndex !== undefined && savedState.currentIndex >= 0) 
                            ? savedState.currentIndex 
                            : 0;
                    } else {
                        this.currentIndex = -1;
                    }
                }
                
                this.isInitialized = true;
                console.log('OSIPicta initialized');

                // Если окно было открыто "Открыть с помощью..." — догружаем файл после инициализации
                try {
                    if (this.pendingFileId) {
                        const fileData = await dFiles.getInfo(this.pendingFileId);
                        this.pendingFileId = null;
                        if (fileData) await this.loadFileFromData(fileData, { replaceList: true });
                    } else if (this.pendingFileData) {
                        const fileData = this.pendingFileData;
                        this.pendingFileData = null;
                        await this.loadFileFromData(fileData, { replaceList: true });
                    } else if (this.fileData && this.images.length === 0) {
                        await this.loadFileFromData(this.fileData, { replaceList: true });
                    }
                } catch (error) {
                    console.error('Failed to load initial file:', error);
                }
            },

            LangData(key) { return this.lang_data[key] || ''; },

            showError(message) {
                alert(message);
                console.error(message);
            },

            // Загрузка файла из переданных данных
            async loadFileFromData(fileData, options = {}) {                
                if (!fileData) {
                    console.error('[FUNC ERR] loadFileFromData:: fileData пустой');
                    this.showError('Нет данных файла');
                    return;
                }

                try {
                    this.isLoading = true;
                    
                    // Пытаемся извлечь файл из разных структур
                    let imgFile = null;
                    let imgBlob = null;

                    // Вариант 1: fileData это сам файл (File или Blob)
                    if (fileData instanceof File || fileData instanceof Blob) {
                        imgFile = fileData;
                        imgBlob = fileData;
                    }
                    // Вариант 2: fileData содержит blob (из DFile)
                    else if (fileData.blob || fileData.data) {
                        const blobLike = fileData.blob || fileData.data;
                        const fileName = fileData.name || this.fileName || 'image';
                        const fileType = fileData.type || this.fileType || 'image/*';

                        if (blobLike instanceof Blob || blobLike instanceof File) {
                            imgBlob = blobLike;
                        } else {
                            imgBlob = new Blob([blobLike], { type: fileType });
                        }

                        imgFile = new File([imgBlob], fileName, { type: fileType });
                    } else if (fileData?.id) {
                        // Вариант 3: есть только id (например, при запуске из DirDigger)
                        const idbFile = await dFiles.getInfo(fileData.id);
                        return await this.loadFileFromData(idbFile, options);
                    }

                    if (!imgFile) {
                        this.showError('Не удалось получить данные изображения');
                        return;
                    }

                    // При запуске "Открыть с помощью..." логично заменить текущий список
                    if (options.replaceList) {
                        this.clearImageList();
                    }

                    // Создаем URL для отображения
                    const dataUrl = URL.createObjectURL(imgFile);
                    this.images.push({
                        file: imgFile,
                        dataUrl,
                        name: imgFile.name,
                        type: imgFile.type,
                        size: imgFile.size,
                        lastModified: imgFile.lastModified || Date.now(),
                    });

                    this.currentIndex = 0;
                    this.$nextTick(() => {
                        this.onImageLoad();
                    });
                    this.throttledSaveState();

                } catch (error) {
                    console.error('[FUNC ERR] loadFileFromData:: Critical Error upload file:', error);
                    this.showError(`Ошибка загрузки файла: ${error.message}`);
                } finally {
                    this.isLoading = false;
                }
            },

            throttledSaveState() {
                if (this.saveTimeout) clearTimeout(this.saveTimeout);
            
                this.saveTimeout = setTimeout(() => {
                    this.saveState();
                    this.saveTimeout = null;
                }, 2000);
            },

            openFilePicker() { 
                this.$refs.fileInput.click(); 
            },

            fileToDataUrl(file) {
                return new Promise((resolve, reject) => {
                    const reader = new FileReader();
                    
                    reader.onload = (e) => resolve(e.target.result);
                    reader.onerror = (e) => reject(e);
                    reader.readAsDataURL(file);
                });
            },

            async handleFileSelect(event) {
                const files = Array.from(event.target.files);
                
                // Добавить фильтрацию по типу
                const imageFiles = files.filter(file => file.type.startsWith('image/'));
                
                if (imageFiles.length !== files.length) {
                    alert(`Пропущено ${files.length - imageFiles.length} не-изображений`);
                }
                
                await this.loadImages(imageFiles);
    
                event.target.value = '';

                if (this.isInitialized) this.saveState();
            },

            async loadImages(files) {
                this.isLoading = true;
                
                try {
                    const newImages = [];
                    
                    for (const file of files) {
                        const dataUrl = await this.fileToDataUrl(file);
                        
                        newImages.push({
                            file,
                            dataUrl,
                            name: file.name,
                            type: file.type,
                            size: file.size,
                            lastModified: file.lastModified
                        });
                    }
                    
                    this.images = [
                        ...this.images,
                        ...newImages
                    ];
                    
                    if (this.images.length > 0 && this.currentIndex === -1) {
                        this.currentIndex = 0;
                        this.$nextTick(() => {
                            this.onImageLoad();
                        });
                    }
                    
                } catch (error) {
                    console.error('Ошибка загрузки изображений:', error);
                    alert('Не удалось загрузить изображения');
                } finally {
                    this.isLoading = false;
                }
            },

            onImageLoad() {
                const img = this.$refs.image;
                if (img) {
                    this.imageNaturalWidth = img.naturalWidth;
                    this.imageNaturalHeight = img.naturalHeight;
                }
                this.Prepare_fileInfo();
                this.$nextTick(() => {
                    this.scrollToSelectedThumbnail();
                    this.fitToWindow(); // Вместо resetView
                });
            },

            resetView() {
                // Сбрасываем масштаб и режим зума
                this.scale = 1;
                this.isZoomed = false;
                
                // Подгоняем изображение под окно, если оно большое
                this.$nextTick(() => {
                    this.fitToWindow();
                });
            },

            zoomIn() {
                this.scale = Math.min(this.scale * 1.2, 3);
                this.isZoomed = this.scale !== 1;
            },

            zoomOut() {
                this.scale = Math.max(this.scale * 0.8, 0.1);
                this.isZoomed = this.scale !== 1;
            },

            fitToWindow() {
                if (!this.currentImage || !this.$refs.image || !this.$refs.viewport) return;
                
                const viewport = this.$refs.viewport;
                const img = this.$refs.image;
                
                if (img.complete) {
                    const scaleX = viewport.clientWidth / img.naturalWidth;
                    const scaleY = viewport.clientHeight / img.naturalHeight;
                    
                    // Если изображение меньше окна по обоим измерениям - показываем в оригинальном размере
                    if (img.naturalWidth <= viewport.clientWidth && img.naturalHeight <= viewport.clientHeight) {
                        this.scale = 1; // Оригинальный размер для маленьких картинок
                    } else {
                        // Для больших картинок - подгоняем под окно
                        this.scale = Math.min(scaleX, scaleY, 1);
                    }
                    
                    this.isZoomed = this.scale !== 1;
                    this.throttledSaveState();
                }
            },

            async Chng_currentIndex(operVal) {
                let newVal = this.currentIndex;

                if (operVal === 'min' && this.currentIndex > 0) {
                    newVal = this.currentIndex - 1;
                } else if (operVal === 'min') {
                    newVal = 0;
                } else if (operVal === 'plus' && this.currentIndex < (this.images.length - 1)) {
                    newVal = this.currentIndex + 1;
                } else if (operVal === 'plus') {
                    newVal = this.images.length - 1;
                } else {
                    newVal = this.currentIndex;
                }
                
                this.currentIndex = newVal;

                // if (!this.isInitialized) this.initFromIDB();

                this.$nextTick(() => {
                    this.scrollToSelectedThumbnail();
                    this.Prepare_fileInfo();
                    this.fitToWindow(); // Вместо resetView
                });
            },

            onImageError() { alert('Не удалось загрузить изображение'); },

            formatFileSize(bytes) {
                if (bytes === 0) return '0 Б';
                const k = 1024;
                const sizes = ['Б', 'КБ', 'МБ', 'ГБ'];
                const i = Math.floor(Math.log(bytes) / Math.log(k));
                return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
            },

            formatDate(timestamp) {
                return new Date(timestamp).toLocaleString();
            },

            MakeHandSelectImg(p) {
                let targetIndex = this.images.findIndex(elem => elem.dataUrl === p.dataUrl);
                if (targetIndex !== -1) {
                    this.currentIndex = targetIndex;
                    this.Prepare_fileInfo();
                    this.$nextTick(() => {
                        this.scrollToSelectedThumbnail();
                        this.fitToWindow(); // Вместо resetView
                    });
                }

                if (this.isInitialized) this.saveState();
            },

            Prepare_fileInfo() {
                if (!this.currentImage) return;
                
                const img = this.$refs.image;
                this.currentImageInfo = {
                    ...this.currentImage,
                    width: img ? img.naturalWidth : 0,
                    height: img ? img.naturalHeight : 0
                };
            },

            setSelectedThumbnailRef(el) {
                this.selectedThumbnailRef = el;
            },

            scrollToSelectedThumbnail() {
                if (this.selectedThumbnailRef && this.$refs.thumbnailList) {
                    const container = this.$refs.thumbnailList;
                    const thumbnail = this.selectedThumbnailRef;
                    
                    const containerWidth = container.clientWidth;
                    const thumbnailLeft = thumbnail.offsetLeft;
                    const thumbnailWidth = thumbnail.clientWidth;
                    
                    const scrollPosition = thumbnailLeft - (containerWidth / 2) + (thumbnailWidth / 2);
                    
                    container.scrollTo({
                        left: scrollPosition,
                        behavior: 'smooth'
                    });
                    
                    this.updateScrollButtons();
                }
            },

            onThumbnailScroll() { this.updateScrollButtons(); },

            updateScrollButtons() {
                if (this.$refs.thumbnailList) {
                    const container = this.$refs.thumbnailList;
                    this.canScrollLeft = container.scrollLeft > 0;
                    this.canScrollRight = container.scrollLeft < (container.scrollWidth - container.clientWidth - 5);
                }
            },

            // очистка списка
            clearImageList() {
                // Очищаем dataUrl для предотвращения утечек памяти
                this.images.forEach(img => {
                    if (img.dataUrl && img.dataUrl.startsWith('blob:')) {
                        URL.revokeObjectURL(img.dataUrl);
                    }
                });
                
                this.images = [];
                this.isLoading = false;
                this.currentIndex = -1;
                this.scale = 1;

                if (this.isInitialized) this.saveState();
            },

            DelElemImg(image) {
                // Находим индекс удаляемого изображения
                const index = this.images.findIndex(img => img.dataUrl === image.dataUrl);
                
                if (index === -1) return;
                
                // Освобождаем blob: URL при удалении элемента
                const removed = this.images[index];
                if (removed?.dataUrl && typeof removed.dataUrl === 'string' && removed.dataUrl.startsWith('blob:')) {
                    try { URL.revokeObjectURL(removed.dataUrl); } catch (e) { /* ignore */ }
                }

                // Удаляем изображение из массива
                this.images.splice(index, 1);
                
                // Корректируем текущий индекс
                if (this.images.length === 0) {
                    // Если изображений не осталось
                    this.currentIndex = -1;
                    this.currentImageInfo = {};
                    this.isZoomed = false;
                    this.scale = 1;
                } else {
                    // Если удалили текущее изображение
                    if (this.currentIndex === index) {
                        // Переходим на предыдущее изображение, если оно есть, иначе на следующее
                        if (index > 0) {
                            this.currentIndex = index - 1;
                        } else {
                            this.currentIndex = 0;
                        }
                    } else if (this.currentIndex > index) {
                        // Если удалили изображение до текущего, сдвигаем индекс
                        this.currentIndex = this.currentIndex - 1;
                    }
                    
                    // Обновляем информацию о текущем изображении
                    this.$nextTick(() => {
                        this.Prepare_fileInfo();
                        this.scrollToSelectedThumbnail();
                        this.fitToWindow();
                    });
                }

                if (this.isInitialized) this.saveState();
            },

            // работа с кнопками стрелочки
            handleKeyPress(e) {
                if (!this.images.length) return;
                
                switch(e.key) {
                    case 'ArrowLeft':
                        this.Chng_currentIndex('min');
                        break;
                    case 'ArrowRight':
                        this.Chng_currentIndex('plus');
                        break;
                    case 'Escape':
                        this.infoPanelVisible = false;
                        break;
                    case '+':
                    case '=':
                        this.zoomIn();
                        break;
                    case '-':
                        this.zoomOut();
                        break;
                    case '0':
                        this.resetView();
                        break;
                }
            },

            // работа с колесиком
            handleWheel(e) {
                if (!this.currentImage) return;
                
                e.preventDefault();
                
                if (e.deltaY < 0) {
                    this.zoomIn();
                } else {
                    this.zoomOut();
                }
            },

            // Сохраняем текущее состояние
            async saveState() {
                console.log('START:: saveState');
                if (!this.windowId || !this.isInitialized) return;
                
                const state = {
                    appType: 'picta',
                    images: this.images,
                    currentIndex: this.currentIndex,
                    timestamp: Date.now()
                };

                await usersTable.windstates.updateVal(this.USERID, this.windowId, state);
            },
        },

        mounted() {
            // Инициализируем данные из store после монтирования
            this.$nextTick(() => {
                this.initFromIDB();
            });

            const userLang = navigator.language || navigator.userLanguage;
            const userLangS = userLang.split('-')[0];
            
            this.UserLang = userLangS; 
            
            const LangPackData = LangPack;

            this.lang_data = (userLangS && LangPackData && LangPackData[userLangS]) ? LangPackData[userLangS] : LangPackData.en;

            window.addEventListener('resize', this.updateScrollButtons);
            window.addEventListener('keydown', this.handleKeyPress);
            this.$refs.viewport.addEventListener('wheel', this.handleWheel, { passive: false });

            // Сохраняем начальное состояние после небольшой задержки
            setTimeout(() => {
                if (!this.isInitialized) this.initFromIDB();

                this.saveState();
            }, 100);
        },

        beforeUnmount() {
            window.removeEventListener('resize', this.updateScrollButtons);
            window.removeEventListener('keydown', this.handleKeyPress);
            this.$refs.viewport.removeEventListener('wheel', this.handleWheel);            
            
            if (this.saveTimeout) clearTimeout(this.saveTimeout);
        }
    }
</script>